const r = $input.item.json;
const nome = r.nome || 'cliente';
const valor = Number(r.valor || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 });
const etapa = String(r.etapa || '');
const educacional = etapa.indexOf('Educacional') === 0;
let assunto, texto, cor, botao;
if (educacional) {
  assunto = 'Lembrete sobre a sua fatura';
  texto = 'Passando para lembrar da sua fatura no valor de R$ ' + valor + '. Qualquer duvida, estamos a disposicao para ajudar.';
  cor = '#3B6D11'; botao = 'Ver detalhes';
} else {
  assunto = 'Pendencia financeira em aberto';
  texto = 'Sua fatura no valor de R$ ' + valor + ' continua em aberto. Para evitar encargos e negativacao, regularize o quanto antes ou fale com a gente.';
  cor = '#27500A'; botao = 'Regularizar agora';
}
const html = ['<div style="font-family:Arial,Helvetica,sans-serif;max-width:600px;margin:0 auto;border:1px solid #C0DD97;border-radius:12px;overflow:hidden;">','<div style="background:' + cor + ';color:#EAF3DE;padding:20px 28px;font-size:20px;font-weight:bold;">Kard</div>','<div style="padding:28px;color:#173404;">','<p style="font-size:17px;margin:0 0 14px;">Ola, ' + nome + '!</p>','<p style="font-size:15px;line-height:1.6;color:#27500A;margin:0 0 22px;">' + texto + '</p>','<a href="https://kard.com.br" style="display:inline-block;background:' + cor + ';color:#EAF3DE;text-decoration:none;font-size:15px;font-weight:bold;padding:12px 26px;border-radius:8px;">' + botao + '</a>','</div>','<div style="background:#EAF3DE;padding:16px 28px;text-align:center;font-size:12px;color:#3B6D11;">Kard - ' + etapa + '.</div>','</div>'].join('');
r.assunto = assunto;
r.html = html;
return $input.item;
